#include <algorithm>
using namespace std;

int binarySearch(vector<int>& arr, int target) {
    int left = 0, right = arr.size() - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] == target) return mid;
        else if (arr[mid] < target) left = mid + 1;
        else right = mid - 1;
    }
    return -1;
}

int main() {
    vector<int> nums = {1, 3, 5, 7, 9, 11, 13};
    cout << binarySearch(nums, 7) << endl;
    return 0;
}

#include <iostream>
#include <stack>
#include <string>
#include <unordered_map>
using namespace std;

bool isBalanced(const string& expr) {
    stack<char> st;
    unordered_map<char, char> pairs = {
        {')', '('},
        {']', '['},
        {'}', '{'}
    };
    for (char ch : expr) {
        if (ch == '(' || ch == '[' || ch == '{') {
            st.push(ch);
        } else if (pairs.count(ch)) {
            if (st.empty() || st.top() != pairs[ch]) {
                return false;
            }
            st.pop();
        }
    }
    return st.empty();
}

int main() {
    vector<string> tests = {
        "{[()]}",
        "((()))",
        "{[(])}",
        "[{]"
    };
    for (const auto& t : tests) {
        cout << t << " -> " << (isBalanced(t) ? "Balanced" : "Not Balanced") << endl;
    }
    return 0;
}
